SELECT i.species_id, i.species_name, g.data_id
FROM insect_species i
INNER JOIN growth_data g ON i.species_id = g.species_id;

SELECT COUNT(*)
FROM insect_species
WHERE geographical_distribution = 'Global distribution, especially in Asia, Europe, and Americas';

SELECT scientific_name 
FROM insect_species 
WHERE geographical_distribution LIKE '%Global distribution, especially in Asia, Europe, and Americas%';

SELECT al.access_id, al.data_id, al.user_id, al.access_date, al.access_type, al.ip_address, al.user_agent
FROM access_logs al
WHERE al.data_id IN (
    SELECT data_id FROM growth_data 
    WHERE species_id = (SELECT species_id FROM insect_species WHERE species_name = 'Aedes albopictus')
);
